def _ai_governance_mode() -> str:
    try:
        raw = str(_read_media_analysis_preferences().get("resolve_ai_governance_mode") or "").strip().lower()
        return raw if raw in _AI_GOVERNANCE_MODES else "advisory"
    except Exception:
        return "advisory"

def _ai_governance_gate(op: str, p: Dict[str, Any]) -> Optional[Dict[str, Any]]:
    """Hard gate for a governed AI render op when governance mode is 'enforce'.

    Returns None to proceed (advisory mode, within tier, or explicit
    override_governance=True), otherwise a destructive_blocked error naming
    the exceeded dimensions. Checked before token issuance so the agent
    learns about the block without burning a confirm round-trip.
    """
    if _ai_governance_mode() != "enforce":
        return None
    if p.get("override_governance") or p.get("overrideGovernance"):
        return None
    check = _ai_governance_check(op)
    if not check.get("applies") or not check.get("exceeded"):
        return None
    return _err(
        f"Governance tier '{check.get('tier')}' blocks this {op} run: "
        + " ".join(check.get("warnings") or ["over threshold."]),
        code="GOVERNANCE_BLOCKED",
        category="destructive_blocked",
        retryable=False,
        remediation=(
            "Raise the tier or thresholds via media_analysis(action='set_ai_governance'), "
            "switch governance mode back to 'advisory', or re-call with override_governance=true "
            "to consciously exceed the tier this once."
        ),
        state={
            "op": op,
            "mode": "enforce",
            "tier": check.get("tier"),
            "usage": check.get("usage"),
            "projected": check.get("projected"),
            "thresholds": check.get("thresholds"),
        },
    )

def _run_maybe_background(label: str, params: Dict[str, Any], fn):
    """Run a long Resolve operation synchronously, or off-thread when requested.

    When params carries a truthy `background` (alias `async_job`), start a polled
    job and return its id at once; otherwise run fn inside long_resolve_op and
    return its result, preserving the synchronous contract.
    """
    if params.get("background") or params.get("async_job"):
        job_id = background_jobs.start_job(label, fn)
        return {
            "success": True,
            "job_id": job_id,
            "status": "running",
            "label": label,
            "note": "poll with resolve_control(action='job_status', params={'job_id': ...})",
        }
    with long_resolve_op(label):
        return fn()

def _record_action_outcome(scope_key: Optional[str], action_name: str,
                            response: Dict[str, Any]) -> Dict[str, Any]:
    """E2 — record the (scope, action) outcome with the failure tracker and
    attach an `escalation` block to the response if the tracker says so.

    Callers should pass the already-built response (the `_err(...)` or `_ok(...)`
    return value); this helper mutates and returns it. A response with no
    `error` key is treated as a success and clears any prior failures.

    Wiring strategy: opt-in. Callers in high-blast-radius paths (analyze_clip,
    commit_vision, safe_apply_drx, etc.) should wrap their final return with
    this helper. Leaving it off for low-stakes reads (probe_*, *_capabilities)
    keeps the tracker focused on signals that matter.
    """
    try:
        from src.core import failure_tracker as _ft
    except Exception:
        return response
    err = response.get("error") if isinstance(response, dict) else None
    if err and isinstance(err, dict):
        category = err.get("category") or "resolve_api_failed"
        _ft.record_failure(scope_key, action_name)
        block = _ft.build_escalation_block(scope_key, action_name, category)
        if block:
            response["escalation"] = block
    else:
        _ft.record_success(scope_key, action_name)
    return response

def _confirm_token_fingerprint(action: str, params: Optional[Dict[str, Any]]) -> str:
    """Stable hash of (action, params) that identifies one specific mutation request."""
    payload = {"action": action, "params": params or {}}
    # Strip the confirm_token itself if the caller is echoing it back to us.
    if isinstance(payload["params"], dict) and "confirm_token" in payload["params"]:
        payload["params"] = {k: v for k, v in payload["params"].items() if k != "confirm_token"}
    try:
        blob = json.dumps(payload, sort_keys=True, default=str)
    except Exception:
        blob = repr(payload)
    return _hashlib.sha256(blob.encode("utf-8")).hexdigest()[:16]

def _confirm_token_gc():
    """Drop expired tokens; called on every issue/validate. Caller may already
    hold _CONFIRM_TOKENS_LOCK (RLock makes re-entry safe)."""
    now = _time.time()
    with _CONFIRM_TOKENS_LOCK:
        expired = [t for t, rec in _CONFIRM_TOKENS.items() if rec.get("expires_at", 0) < now]
        for t in expired:
            _CONFIRM_TOKENS.pop(t, None)

def _confirm_token_required() -> bool:
    """Honor setup default destructive.require_confirm_token (default True)."""
    try:
        prefs = _read_media_analysis_preferences() if "_read_media_analysis_preferences" in globals() else {}
    except Exception:
        prefs = {}
    destructive = prefs.get("destructive") if isinstance(prefs.get("destructive"), dict) else {}
    val = destructive.get("require_confirm_token", True)
    if isinstance(val, str):
        return val.strip().lower() not in {"0", "false", "no", "off"}
    return bool(val)

def _issue_confirm_token(*, action: str, params: Optional[Dict[str, Any]], preview: Dict[str, Any]) -> Dict[str, Any]:
    """Mint a token. Returns the pending_user_decision response shape."""
    token = _uuid.uuid4().hex
    fp = _confirm_token_fingerprint(action, params)
    expires_at = _time.time() + _CONFIRM_TTL_SECONDS
    with _CONFIRM_TOKENS_LOCK:
        _confirm_token_gc()
        _CONFIRM_TOKENS[token] = {
            "action": action,
            "fingerprint": fp,
            "expires_at": expires_at,
            "issued_at": _time.time(),
        }
    body = _err(
        "This action is destructive. Re-call with confirm_token to proceed.",
        code="CONFIRMATION_REQUIRED",
        category="pending_user_decision",
        retryable=False,
        remediation=f"Re-call {action} with params.confirm_token={token!r}; token expires in {_CONFIRM_TTL_SECONDS}s.",
    )
    body.update({
        "status": "confirmation_required",
        "confirm_token": token,
        "preview": preview,
        "expires_at_epoch": expires_at,
        "ttl_seconds": _CONFIRM_TTL_SECONDS,
    })
    return body

def _consume_confirm_token(*, action: str, params: Optional[Dict[str, Any]]) -> Optional[Dict[str, Any]]:
    """If a valid token is present, consume it and return None (proceed).
    If missing/expired/mismatched, return a destructive_blocked error.
    If gating is disabled, return None (proceed).
    """
    if not _confirm_token_required():
        return None
    token = (params or {}).get("confirm_token") or (params or {}).get("confirmToken")
    if not token:
        return None  # Caller is expected to call _issue_confirm_token in this case.
    with _CONFIRM_TOKENS_LOCK:
        _confirm_token_gc()
        rec = _CONFIRM_TOKENS.pop(token, None)  # one-time use, atomic with gc
    if rec is None:
        return _err(
            "confirm_token is invalid, expired, or was issued by a different "
            "server instance (tokens are valid only on the instance that "
            "issued them — e.g. a stdio-server token is not honored by the "
            "networked server).",
            code="CONFIRM_TOKEN_INVALID",
            category="destructive_blocked",
            retryable=False,
            remediation=f"Re-call {action} without confirm_token on this instance to receive a fresh token.",
        )
    if rec.get("action") != action:
        return _err(
            f"confirm_token issued for {rec.get('action')!r}, not {action!r}",
            code="CONFIRM_TOKEN_ACTION_MISMATCH",
            category="destructive_blocked",
            retryable=False,
        )
    if rec.get("fingerprint") != _confirm_token_fingerprint(action, params):
        return _err(
            "confirm_token does not match the current params",
            code="CONFIRM_TOKEN_FINGERPRINT_MISMATCH",
            category="destructive_blocked",
            retryable=False,
            remediation="Either re-issue the token with current params or roll back the params change.",
        )
    return None  # OK to proceed

def _activate_resolve_window() -> Dict[str, Any]:
    """Bring DaVinci Resolve to the foreground.

    macOS: AppleScript `tell application "DaVinci Resolve" to activate`.
    Windows: PowerShell `(New-Object -ComObject WScript.Shell).AppActivate(...)`.
    Linux: wmctrl/xdotool if present.

    Best-effort; returns {activated: bool, platform, error?}. Never raises.
    """
    try:
        if sys.platform == "darwin":
            import subprocess
            proc = subprocess.run(
                ["osascript", "-e", 'tell application "DaVinci Resolve" to activate'],
                capture_output=True, text=True, timeout=5,
                stdin=subprocess.DEVNULL,
            )
            return {
                "activated": proc.returncode == 0,
                "platform": "darwin",
                "error": proc.stderr.strip() if proc.returncode != 0 else None,
            }
        if sys.platform.startswith("win"):
            import subprocess
            proc = subprocess.run(
                ["powershell", "-NoProfile", "-Command",
                 "$s = New-Object -ComObject WScript.Shell; "
                 "$null = $s.AppActivate('DaVinci Resolve')"],
                capture_output=True, text=True, timeout=5,
                stdin=subprocess.DEVNULL,
            )
            return {
                "activated": proc.returncode == 0,
                "platform": "win32",
                "error": proc.stderr.strip() if proc.returncode != 0 else None,
            }
        # Linux: try wmctrl, then xdotool. Quietly no-op if neither present.
        import subprocess
        import shutil
        if shutil.which("wmctrl"):
            proc = subprocess.run(
                ["wmctrl", "-a", "DaVinci Resolve"],
                capture_output=True, text=True, timeout=5,
                stdin=subprocess.DEVNULL,
            )
            return {
                "activated": proc.returncode == 0,
                "platform": "linux",
                "tool": "wmctrl",
            }
        if shutil.which("xdotool"):
            proc = subprocess.run(
                ["xdotool", "search", "--name", "DaVinci Resolve", "windowactivate"],
                capture_output=True, text=True, timeout=5,
                stdin=subprocess.DEVNULL,
            )
            return {
                "activated": proc.returncode == 0,
                "platform": "linux",
                "tool": "xdotool",
            }
        return {"activated": False, "platform": sys.platform, "note": "no window-manager tool found"}
    except Exception as exc:
        return {"activated": False, "error": f"{type(exc).__name__}: {exc}"}

def _send_resolve_keystroke_go_to_mark_in() -> Dict[str, Any]:
    """Send the Resolve keyboard shortcut for "Go to In" (Shift+I).

    Resolve's scripting API has no direct call to move the source-viewer
    playhead, so we use the OS-level keystroke once the app is focused.
    Best-effort; returns {sent: bool, platform, error?}.
    """
    try:
        if sys.platform == "darwin":
            import subprocess
            # Tiny pause lets the just-activated app settle before receiving keys.
            script = (
                'delay 0.15\n'
                'tell application "System Events" to tell process "DaVinci Resolve"\n'
                '    key code 34 using {shift down}\n'  # 34 = 'i'
                'end tell'
            )
            proc = subprocess.run(
                ["osascript", "-e", script],
                capture_output=True, text=True, timeout=5,
                stdin=subprocess.DEVNULL,
            )
            return {
                "sent": proc.returncode == 0,
                "platform": "darwin",
                "shortcut": "Shift+I",
                "error": proc.stderr.strip() if proc.returncode != 0 else None,
            }
        if sys.platform.startswith("win"):
            import subprocess
            proc = subprocess.run(
                ["powershell", "-NoProfile", "-Command",
                 "Add-Type -AssemblyName System.Windows.Forms; "
                 "Start-Sleep -Milliseconds 150; "
                 "[System.Windows.Forms.SendKeys]::SendWait('+i')"],
                capture_output=True, text=True, timeout=5,
                stdin=subprocess.DEVNULL,
            )
            return {
                "sent": proc.returncode == 0,
                "platform": "win32",
                "shortcut": "Shift+I",
                "error": proc.stderr.strip() if proc.returncode != 0 else None,
            }
        # Linux: try xdotool only (wmctrl can't send keys).
        import subprocess
        import shutil
        if shutil.which("xdotool"):
            proc = subprocess.run(
                ["xdotool", "search", "--name", "DaVinci Resolve", "key", "--window", "%@", "shift+i"],
                capture_output=True, text=True, timeout=5,
                stdin=subprocess.DEVNULL,
            )
            return {"sent": proc.returncode == 0, "platform": "linux", "tool": "xdotool", "shortcut": "Shift+I"}
        return {"sent": False, "platform": sys.platform, "note": "no key-send tool found"}
    except Exception as exc:
        return {"sent": False, "error": f"{type(exc).__name__}: {exc}"}



def _is_truncated(text):
    """True if a transcription preview was cut off.

    Resolve's `Transcription` clip property is a preview that ends with an
    ellipsis (… or ...) when the full transcript is longer than the property
    exposes, so the caller knows the returned text is partial.
    """
    if not isinstance(text, str):
        return False
    t = text.rstrip()
    return t.endswith("…") or t.endswith("...")

def _first_param(p: Dict[str, Any], *keys: str, default=None):
    for key in keys:
        if key in p and p[key] is not None:
            return p[key]
    return default


def _find_timeline_item_by_id(tl, timeline_item_id) -> Optional[Any]:
    """Find a timeline item by GetUniqueId() across timeline tracks."""
    if not timeline_item_id:
        return None
    want = str(timeline_item_id)
    for track_type in ("video", "audio", "subtitle"):
        try:
            track_count = int(tl.GetTrackCount(track_type) or 0)
        except Exception as exc:
            # Don't silently skip a whole track type on API error — log it so a
            # genuine API failure isn't mistaken for "item not found" (EX10).
            logger.warning("_find_timeline_item_by_id: GetTrackCount(%s) failed, skipping: %s", track_type, exc)
            continue
        for track_index in range(1, track_count + 1):
            for item in (tl.GetItemListInTrack(track_type, track_index) or []):
                try:
                    if str(item.GetUniqueId()) == want:
                        return item
                except Exception:
                    continue
    return None

def _timeline_items_by_ids(tl, ids, track_types=("video", "audio", "subtitle")):
    ids_set = {str(item_id) for item_id in ids if item_id is not None}
    found = []
    if not ids_set:
        return found
    for track_type in track_types:
        for track_index in range(1, _timeline_track_count(tl, track_type) + 1):
            for item in (tl.GetItemListInTrack(track_type, track_index) or []):
                if _safe_timeline_item_id(item) in ids_set:
                    found.append(item)
    return found






def _timeline_resolve_item_optional(tl, p: Dict[str, Any]):
    """Resolve a single timeline item from clip_id, timeline_item_id, or timeline_item scope."""
    item_id = p.get("clip_id") or p.get("timeline_item_id")
    if item_id:
        item = _find_timeline_item_by_id(tl, item_id)
        if not item:
            return None, _err(f"No timeline item with clip_id/timeline_item_id={item_id!r}")
        return item, None
    if p.get("timeline_item"):
        _, item, item_err = _get_item(p["timeline_item"])
        if item_err:
            return None, item_err
        return item, None
    return None, _err("requires clip_id, timeline_item_id, or timeline_item={track_type, track_index, item_index}")

def _timeline_items_by_ids_report(tl, ids: List[Any], track_types=("video", "audio")) -> Tuple[List[Any], List[str]]:
    found = _timeline_items_by_ids(tl, ids, track_types=track_types)
    found_ids = {_safe_timeline_item_id(item) for item in found}
    missing = [str(item_id) for item_id in ids if str(item_id) not in found_ids]
    return found, missing

def _thumbnail_raw_rgb(thumbnail_data: Dict[str, Any]) -> Tuple[int, int, bytes]:
    width = int(thumbnail_data.get("width") or 0)
    height = int(thumbnail_data.get("height") or 0)
    components = int(thumbnail_data.get("noOfComponents") or thumbnail_data.get("components") or thumbnail_data.get("channels") or 3)
    data = thumbnail_data.get("data")
    if isinstance(data, str):
        raw = base64.b64decode(data)
    elif isinstance(data, bytes):
        raw = data
    elif isinstance(data, bytearray):
        raw = bytes(data)
    elif isinstance(data, list):
        raw = bytes(data)
    else:
        raise ValueError(f"Unsupported thumbnail data type: {type(data).__name__}")
    if width <= 0 or height <= 0 or components not in (3, 4):
        raise ValueError("Unsupported thumbnail shape")
    expected = width * height * components
    if len(raw) < expected:
        raise ValueError("Thumbnail data is shorter than expected")
    raw = raw[:expected]
    if components == 3:
        return width, height, raw
    rgb = bytearray()
    for index in range(0, len(raw), 4):
        rgb.extend(raw[index:index + 3])
    return width, height, bytes(rgb)

def _rgb_to_png_bytes(width: int, height: int, raw_rgb: bytes) -> bytes:
    row_size = width * 3
    filtered_rows = bytearray()
    for y in range(height):
        filtered_rows.append(0)
        start = y * row_size
        filtered_rows.extend(raw_rgb[start:start + row_size])
    ihdr = struct.pack(">IIBBBBB", width, height, 8, 2, 0, 0, 0)
    return (
        b"\x89PNG\r\n\x1a\n"
        + _png_chunk(b"IHDR", ihdr)
        + _png_chunk(b"IDAT", zlib.compress(bytes(filtered_rows)))
        + _png_chunk(b"IEND", b"")
    )

def _draw_rect_rgb(canvas: bytearray, canvas_w: int, canvas_h: int, x: int, y: int, w: int, h: int, color: Tuple[int, int, int]) -> None:
    x0 = max(0, x)
    y0 = max(0, y)
    x1 = min(canvas_w, x + w)
    y1 = min(canvas_h, y + h)
    for yy in range(y0, y1):
        for xx in range(x0, x1):
            idx = (yy * canvas_w + xx) * 3
            canvas[idx:idx + 3] = bytes(color)

def _draw_tiny_text_rgb(canvas: bytearray, canvas_w: int, canvas_h: int, x: int, y: int, text: str, *, scale: int = 2, color: Tuple[int, int, int] = (235, 235, 235)) -> None:
    cursor = x
    for char in str(text).upper():
        glyph = _TINY_FONT.get(char, ("111", "101", "101", "101", "111"))
        glyph_w = max(len(row) for row in glyph)
        for gy, row in enumerate(glyph):
            for gx, bit in enumerate(row):
                if bit != "1":
                    continue
                _draw_rect_rgb(canvas, canvas_w, canvas_h, cursor + gx * scale, y + gy * scale, scale, scale, color)
        cursor += (glyph_w + 1) * scale

def _contact_sheet_sample_label(sample: Dict[str, Any], index: int) -> str:
    marker = sample.get("marker") or {}
    name = marker.get("name") or marker.get("note") or sample.get("source") or "frame"
    basis = sample.get("timecode") or f"f{sample.get('frame')}"
    label = f"{index:02d} {basis} {name}"
    label = re.sub(r"[^A-Za-z0-9:._/# -]+", " ", str(label))
    return re.sub(r"\s+", " ", label).strip()

def _contact_sheet_png_bytes(samples: List[Dict[str, Any]], columns: int = 4, padding: int = 8, label_height: int = 24) -> Tuple[int, int, bytes]:
    thumbs = [sample for sample in samples if sample.get("thumbnail_rgb")]
    if not thumbs:
        raise ValueError("No thumbnails available for contact sheet")
    thumb_w, thumb_h = thumbs[0]["thumbnail_rgb"][0], thumbs[0]["thumbnail_rgb"][1]
    columns = max(1, min(columns, len(thumbs)))
    rows = int(math.ceil(len(thumbs) / columns))
    label_height = max(0, int(label_height or 0))
    cell_h = thumb_h + label_height
    width = columns * thumb_w + (columns + 1) * padding
    height = rows * cell_h + (rows + 1) * padding
    canvas = bytearray([24, 24, 24] * width * height)
    for sample_index, sample in enumerate(thumbs):
        thumb_w, thumb_h, raw = sample["thumbnail_rgb"]
        col = sample_index % columns
        row = sample_index // columns
        x0 = padding + col * (thumb_w + padding)
        y0 = padding + row * (cell_h + padding)
        for y in range(thumb_h):
            src = y * thumb_w * 3
            dst = ((y0 + y) * width + x0) * 3
            canvas[dst:dst + thumb_w * 3] = raw[src:src + thumb_w * 3]
        if label_height:
            label = sample.get("label") or _contact_sheet_sample_label(sample, sample_index + 1)
            sample["label"] = label
            _draw_rect_rgb(canvas, width, height, x0, y0 + thumb_h, thumb_w, label_height, (12, 12, 12))
            max_chars = max(4, (thumb_w - 8) // 8)
            _draw_tiny_text_rgb(canvas, width, height, x0 + 4, y0 + thumb_h + 5, label[:max_chars], scale=2)
    return width, height, _rgb_to_png_bytes(width, height, bytes(canvas))

def _resolve_enum_settings(resolve_obj, settings, field_specs):
    """Resolve a human-readable settings dict into the live enum-keyed dict that
    enum-keyed Resolve APIs require.

    Several Resolve methods (``MediaPool.AutoSyncAudio``,
    ``Timeline.CreateSubtitlesFromAudio``, the ``ProjectManager`` CloudProject
    family) key their settings dict by ``resolve.<CONST>`` enum attributes — and
    for many fields expect ``resolve.<CONST>`` enum *values* too. They silently
    reject the WHOLE call when handed a plain string key (returning False/None
    with nothing applied), so unrecognized keys must be dropped, not forwarded.
    See core/api_truth.py for the catalogued symbols.

    ``field_specs`` is an iterable of dicts, one per supported field:
      ``aliases``   human keys accepted for this field (case-insensitive)
      ``key_const`` name of the ``resolve`` enum attribute used as the dict key
      ``key_fallback`` key used when the live handle can't resolve ``key_const``
                    (defaults to ``key_const``); keeps offline behavior readable
      ``values``    optional ``{lowercased_str: enum_const_name}`` value map
      ``coerce``    optional ``"int"`` | ``"bool"`` cast for plain values
      ``bounds``    optional ``(min, max)`` clamp applied after int coercion

    Returns ``(normalized, ignored)``. ``ignored`` lists input keys that no spec
    claimed AND recognized keys whose value could not be resolved (sorted) — so a
    field that silently fails to apply is reported rather than hidden.
    """
    if not settings:
        return {}, []
    normalized = {}
    consumed = set()
    lower = {str(k).strip().lower(): k for k in settings}

    for spec in field_specs:
        src_key = next((lower[a.lower()] for a in spec["aliases"] if a.lower() in lower), None)
        if src_key is None:
            continue
        raw = settings[src_key]
        key = _resolve_audio_constant(resolve_obj, spec["key_const"], spec.get("key_fallback", spec["key_const"]))
        values_map = spec.get("values")
        if values_map is not None and isinstance(raw, str):
            const_name = values_map.get(raw.strip().lower())
            if const_name is None:
                continue  # unknown enum value — leave src_key unconsumed -> ignored
            value = _resolve_audio_constant(resolve_obj, const_name, raw)
        elif spec.get("coerce") == "int":
            try:
                value = int(raw) if not isinstance(raw, bool) else int(raw)
            except (TypeError, ValueError):
                continue
            lo, hi = spec.get("bounds", (None, None))
            if lo is not None:
                value = max(lo, value)
            if hi is not None:
                value = min(hi, value)
        elif spec.get("coerce") == "bool":
            value = bool(raw)
        else:
            value = raw
        normalized[key] = value
        consumed.add(src_key)

    ignored = sorted(str(key) for key in settings if key not in consumed)
    return normalized, ignored


def _read_json_strict(path: str) -> Dict[str, Any]:
    """Read JSON for a read-modify-write cycle.

    Returns ``{}`` only when the file is absent or empty (safe to create). Raises
    :class:`ConfigParseError` when the file exists but cannot be read/parsed, so
    the caller can refuse to overwrite and avoid clobbering prior contents.
    """
    try:
        with open(path, "r", encoding="utf-8") as handle:
            raw = handle.read()
    except FileNotFoundError:
        return {}
    except OSError as exc:
        raise ConfigParseError(f"{path}: {exc}") from exc
    if not raw.strip():
        return {}
    try:
        payload = json.loads(raw)
    except json.JSONDecodeError as exc:
        raise ConfigParseError(f"{path}: {exc}") from exc
    return payload if isinstance(payload, dict) else {}

def _write_media_analysis_preferences(preferences: Dict[str, Any]) -> None:
    # Atomic replace: a crash mid-write must not truncate the file, because the
    # reader resets to {} on corruption and the next save would then wipe every
    # remaining user preference.
    path = _media_analysis_preferences_path()
    os.makedirs(os.path.dirname(path), exist_ok=True)
    tmp_path = f"{path}.tmp-{os.getpid()}-{threading.get_ident()}-{time.time_ns()}"
    try:
        with open(tmp_path, "w", encoding="utf-8") as handle:
            json.dump(preferences, handle, indent=2, sort_keys=True)
            handle.write("\n")
        os.replace(tmp_path, path)
    finally:
        try:
            os.remove(tmp_path)
        except OSError:
            pass

def _setup_text_key(value: Any) -> str:
    return str(value or "").strip().lower().replace("-", "_").replace(" ", "_")

def _normalize_yes_no_ask(value: Any) -> Optional[str]:
    if value is None:
        return None
    if isinstance(value, bool):
        return "yes" if value else "no"
    raw = _setup_text_key(value)
    if raw in {"1", "true", "y", "yes", "on", "enable", "enabled"}:
        return "yes"
    if raw in {"0", "false", "n", "no", "off", "disable", "disabled"}:
        return "no"
    if raw in {"ask", "prompt", "ask_me", "ask_user"}:
        return "ask"
    if raw in _SETUP_CHOICE_CLEAR_VALUES:
        return "ask"
    return None

def _normalize_vision_default(value: Any) -> Optional[str]:
    if value is None:
        return None
    if isinstance(value, bool):
        return "on" if value else "off"
    raw = _setup_text_key(value)
    aliases = {
        "1": "on",
        "true": "on",
        "yes": "on",
        "on": "on",
        "enable": "on",
        "enabled": "on",
        "chat": "on",
        "chat_context": "on",
        "host_chat": "on",
        "host_chat_paths": "on",
        "0": "off",
        "false": "off",
        "no": "off",
        "off": "off",
        "disable": "off",
        "disabled": "off",
        "technical": "technical_only",
        "technical_only": "technical_only",
        "technicalonly": "technical_only",
        "ask": "ask",
        "prompt": "ask",
    }
    return aliases.get(raw)

def _normalize_setup_choice(value: Any, allowed: List[str], aliases: Optional[Dict[str, str]] = None) -> Optional[str]:
    raw = _setup_text_key(value)
    if aliases and raw in aliases:
        raw = aliases[raw]
    return raw if raw in set(allowed) else None

def _normalize_setup_list(value: Any, aliases: Optional[Dict[str, str]] = None, allowed: Optional[List[str]] = None) -> List[str]:
    if value is None:
        return []
    if isinstance(value, str):
        parts = [part.strip() for part in re.split(r"[,;]", value) if part.strip()]
    elif isinstance(value, (list, tuple, set)):
        parts = [str(part).strip() for part in value if str(part).strip()]
    else:
        parts = [str(value).strip()]
    normalized = []
    allowed_set = set(allowed or [])
    for part in parts:
        key = _setup_text_key(part)
        if aliases and key in aliases:
            key = aliases[key]
        if allowed_set and key not in allowed_set:
            continue
        if key and key not in normalized:
            normalized.append(key)
    return normalized

def _setup_positive_int(value: Any, default: int, min_value: int = 0, max_value: int = 9999) -> int:
    try:
        parsed = int(value)
    except (TypeError, ValueError):
        return default
    return max(min_value, min(parsed, max_value))

def _safe_int(value: Any, default: int, *, minimum: Optional[int] = None, maximum: Optional[int] = None) -> int:
    """Coerce a tool param to int without throwing; clamp to [minimum, maximum].

    Used by action handlers so a non-numeric or out-of-range numeric param yields
    a sane value instead of an unhandled ValueError or a SQLite "negative LIMIT =
    no limit" full-table fetch (EX8)."""
    try:
        parsed = int(value)
    except (TypeError, ValueError):
        parsed = default
    if minimum is not None:
        parsed = max(minimum, parsed)
    if maximum is not None:
        parsed = min(parsed, maximum)
    return parsed

def _filter_to_keys(settings: Any, allowed) -> Tuple[Dict[str, Any], list]:
    """Whitelist a settings/options dict to the keys a Resolve API documents.

    Resolve silently ignores unrecognized keys in several options dicts (import
    options, render settings, voice-isolation state), so a typo'd key is dropped
    with no signal. This returns ``(filtered, ignored)`` — only known keys are
    forwarded; ``ignored`` lists the dropped keys so the caller can surface them
    in ``ignored_settings`` (P1 / deep-QC #4-6,23-25)."""
    if not isinstance(settings, dict):
        return {}, []
    allowed_set = set(allowed)
    filtered = {k: v for k, v in settings.items() if k in allowed_set}
    ignored = sorted(str(k) for k in settings if k not in allowed_set)
    return filtered, ignored

def _setup_marker_limit(value: Any, default: int = 12) -> int:
    if isinstance(value, str) and _setup_text_key(value) in {"unlimited", "no_limit", "nolimit", "all"}:
        return 0
    return _setup_positive_int(value, default, 0, 250)

def _normalize_timed_marker_choice(value: Any) -> Optional[str]:
    if value is None:
        return None
    if isinstance(value, dict):
        value = _first_param(value, "choice", "timed_markers", "timedMarkers", "enabled", "write_markers", "writeMarkers")
    if isinstance(value, bool):
        return "yes" if value else "no"
    raw = str(value).strip().lower().replace("-", "_").replace(" ", "_")
    if raw in {"1", "true", "y", "yes", "on", "enable", "enabled"}:
        return "yes"
    if raw in {"0", "false", "n", "no", "off", "disable", "disabled"}:
        return "no"
    if raw in {"default_yes", "yes_default", "always_yes", "yes_always"}:
        return "default_yes"
    if raw in {"default_no", "no_default", "always_no", "no_always"}:
        return "default_no"
    if raw in {"ask", "prompt", "ask_me", "ask_user"}:
        return "ask"
    return None

def _timed_marker_choice_from_params(p: Dict[str, Any]) -> Optional[str]:
    raw = _first_param(
        p,
        "timed_markers",
        "timedMarkers",
        "timed_marker_choice",
        "timedMarkerChoice",
        "marker_choice",
        "markerChoice",
        "write_markers",
        "writeMarkers",
        "marker_writeback",
        "markerWriteback",
        "add_markers",
        "addMarkers",
    )
    if raw is None and isinstance(p.get("markers"), dict):
        raw = _first_param(
            p["markers"],
            "timed_markers",
            "timedMarkers",
            "choice",
            "enabled",
            "write_markers",
            "writeMarkers",
        )
    return _normalize_timed_marker_choice(raw)

def _normalize_sampling_mode_default(value: Any) -> Optional[str]:
    """Resolve a stored sampling_mode_default to a canonical mode, or None.

    None means "not chosen yet" — covers an unset value and the "ask" sentinel,
    both of which should trigger the first-run prompt.
    """
    if value is None:
        return None
    raw = str(value).strip().lower()
    if raw in {"", "ask", "prompt", "ask_me", "ask_user", "none", "unset", "default"}:
        return None
    return normalize_sampling_mode(value, default=None)

def _sampling_mode_choice_from_params(p: Dict[str, Any]) -> Optional[str]:
    """Read an explicit sampling-mode choice from analysis params.

    Returns a canonical mode, the "ask" sentinel, or None when unspecified.
    """
    raw = _first_param(
        p,
        "sampling_mode",
        "samplingMode",
        "frame_sampling_mode",
        "frameSamplingMode",
        "analysis_mode",
        "analysisMode",
    )
    if raw is None and isinstance(p.get("sampling"), dict):
        raw = _first_param(p["sampling"], "mode", "sampling_mode", "samplingMode")
    if raw is None:
        return None
    if str(raw).strip().lower() in {"ask", "prompt", "ask_me", "ask_user"}:
        return "ask"
    return normalize_sampling_mode(raw, default=None)

def _has_any_param(p: Dict[str, Any], *keys: str) -> bool:
    return any(key in p and p[key] is not None for key in keys)

def _path_error(path: str, *, must_be_dir: bool = False, must_be_file: bool = False):
    if not path or not isinstance(path, str):
        return "path must be a non-empty string"
    if not os.path.exists(path):
        return f"path does not exist: {path}"
    if must_be_dir and not os.path.isdir(path):
        return f"path is not a directory: {path}"
    if must_be_file and not os.path.isfile(path):
        return f"path is not a file: {path}"
    return None

def _string_list_param(p: Dict[str, Any], key: str):
    value = p.get(key)
    if not isinstance(value, list) or not value:
        return None, _err(f"{key} must be a non-empty list")
    cleaned = []
    for index, item in enumerate(value):
        if not isinstance(item, str) or not item:
            return None, _err(f"{key}[{index}] must be a non-empty string")
        cleaned.append(item)
    return cleaned, None

def _png_chunk(chunk_type: bytes, chunk_data: bytes) -> bytes:
    payload = chunk_type + chunk_data
    crc = struct.pack(">I", zlib.crc32(payload) & 0xFFFFFFFF)
    return struct.pack(">I", len(chunk_data)) + payload + crc

def _thumbnail_data_to_png_bytes(thumbnail_data: Dict[str, Any]) -> bytes:
    """Convert Resolve's raw thumbnail dict into PNG bytes."""
    if not isinstance(thumbnail_data, dict):
        raise ValueError("thumbnail_data must be a dict")

    width = int(thumbnail_data.get("width") or 0)
    height = int(thumbnail_data.get("height") or 0)
    components = int(
        thumbnail_data.get("noOfComponents")
        or thumbnail_data.get("components")
        or thumbnail_data.get("channels")
        or 3
    )
    depth = int(thumbnail_data.get("depth") or 8)
    data = thumbnail_data.get("data")

    if width <= 0 or height <= 0:
        raise ValueError(f"Invalid thumbnail dimensions: {width}x{height}")
    if components not in (3, 4):
        raise ValueError(f"Unsupported thumbnail component count: {components}")
    if depth != 8:
        raise ValueError(f"Unsupported thumbnail bit depth: {depth}")
    if not data:
        raise ValueError("Thumbnail data is empty")

    if isinstance(data, str):
        raw = base64.b64decode(data)
    elif isinstance(data, bytes):
        raw = data
    elif isinstance(data, bytearray):
        raw = bytes(data)
    elif isinstance(data, list):
        raw = bytes(data)
    else:
        raise ValueError(f"Unsupported thumbnail data type: {type(data).__name__}")

    row_size = width * components
    expected_size = row_size * height
    if len(raw) < expected_size:
        raise ValueError(
            f"Thumbnail data too short: got {len(raw)} bytes, expected "
            f"{expected_size} for {width}x{height}x{components}"
        )
    raw = raw[:expected_size]

    filtered_rows = bytearray()
    for y in range(height):
        filtered_rows.append(0)
        start = y * row_size
        filtered_rows.extend(raw[start:start + row_size])

    color_type = 2 if components == 3 else 6
    ihdr = struct.pack(">IIBBBBB", width, height, 8, color_type, 0, 0, 0)
    return (
        b"\x89PNG\r\n\x1a\n"
        + _png_chunk(b"IHDR", ihdr)
        + _png_chunk(b"IDAT", zlib.compress(bytes(filtered_rows)))
        + _png_chunk(b"IEND", b"")
    )

def _settings_diff(requested: Dict[str, Any], applied: Dict[str, Any]):
    if not isinstance(applied, dict):
        return {"matched": [], "coerced_or_missing": sorted(requested.keys())}
    matched = []
    coerced = {}
    for key, value in requested.items():
        if applied.get(key) == value:
            matched.append(key)
        else:
            coerced[key] = {"requested": value, "applied": applied.get(key)}
    return {"matched": sorted(matched), "coerced_or_missing": coerced}

def _opt_number(value: Any) -> Optional[float]:
    """Coerce int/float/numeric-string to float; anything else → None.

    LLM clients routinely stringify numbers; params must not crash (or be
    silently dropped) because "12.5" arrived instead of 12.5.
    """
    if isinstance(value, bool):
        return None
    if isinstance(value, (int, float)):
        return float(value)
    if isinstance(value, str):
        try:
            return float(value.strip())
        except ValueError:
            return None
    return None

def _action_help(tool_name: str, p: Dict[str, Any]) -> Dict[str, Any]:
    """Return long-form guidance + example for a named action on tool_name."""
    name = (p or {}).get("name") or (p or {}).get("action_name")
    catalog = _ACTION_HELP.get(tool_name, {})
    valid = _TOOL_ACTIONS.get(tool_name)
    if not name:
        payload = {
            "tool": tool_name,
            "available": sorted(catalog.keys()),
            "note": "Call action_help with params.name to retrieve guidance for a specific action.",
        }
        if valid is not None:
            payload["actions"] = sorted(valid)
            payload["note"] = ("'available' lists actions with detailed help; 'actions' lists all "
                               "valid actions. Call action_help with params.name for one action.")
        return _ok(**payload)
    entry = catalog.get(name)
    if entry:
        return _ok(tool=tool_name, action=name, **entry)
    if valid is not None and name not in valid:
        return _err(
            f"Unknown action {tool_name}.{name}.",
            code="UNKNOWN_ACTION",
            category="invalid_input",
            remediation=f"Valid actions: {', '.join(sorted(valid))}",
        )
    return _err(
        f"No help registered for {tool_name}.{name}.",
        code="HELP_NOT_REGISTERED",
        category="invalid_input",
        remediation="Call action_help() with no name for the list of actions with detailed help.",
    )


def _read_media_analysis_preferences() -> Dict[str, Any]:
    path = _media_analysis_preferences_path()
    try:
        with open(path, "r", encoding="utf-8") as handle:
            payload = json.load(handle)
        return payload if isinstance(payload, dict) else {}
    except (OSError, json.JSONDecodeError):
        return {}


def _read_media_analysis_preferences_strict() -> Dict[str, Any]:
    """Strict prefs read for read-modify-write paths — raises ConfigParseError on
    a corrupt existing file so the caller refuses to overwrite (PS1)."""
    return _read_json_strict(_media_analysis_preferences_path())


def _media_analysis_effective_preferences() -> Dict[str, Any]:
    preferences = _read_media_analysis_preferences()
    effective = dict(_MEDIA_ANALYSIS_DEFAULT_PREFS)
    for key, value in preferences.items():
        if key in effective:
            effective[key] = value

    timed_default = _normalize_timed_marker_choice(effective.get("timed_markers_default"))
    effective["timed_markers_default"] = timed_default if timed_default in {"yes", "no"} else None
    effective["slate_detection_default"] = _normalize_yes_no_ask(effective.get("slate_detection_default")) or "ask"
    effective["vision_default"] = _normalize_vision_default(effective.get("vision_default")) or "on"
    effective["transcription_default"] = _normalize_yes_no_ask(effective.get("transcription_default")) or "yes"
    effective["analysis_persistence"] = _normalize_analysis_persistence(effective.get("analysis_persistence")) or "session_only"
    effective["metadata_overwrite_policy"] = _normalize_metadata_overwrite_policy(effective.get("metadata_overwrite_policy")) or "preserve_human"
    effective["timed_marker_types"] = _normalize_setup_list(
        effective.get("timed_marker_types"),
        aliases=_MEDIA_ANALYSIS_MARKER_TYPE_ALIASES,
        allowed=["shots", "slate_clap", "sync_events", "best_moments", "qc_warnings"],
    ) or list(_MEDIA_ANALYSIS_DEFAULT_MARKER_TYPES)
    effective["timed_marker_colors"] = {
        **_MEDIA_ANALYSIS_DEFAULT_MARKER_COLORS,
        **_normalize_marker_colors(effective.get("timed_marker_colors")),
    }
    effective["max_timed_markers_per_clip"] = _setup_marker_limit(effective.get("max_timed_markers_per_clip"), 12)
    effective["metadata_publish_fields"] = [
        str(field).strip()
        for field in _media_analysis_as_list(effective.get("metadata_publish_fields"))
        if str(field).strip()
    ] or list(_MEDIA_ANALYSIS_DEFAULT_PUBLISH_FIELDS)
    effective["include_confidence_scores"] = _media_analysis_bool(effective.get("include_confidence_scores"), True)
    effective["include_source_time_notes"] = _media_analysis_bool(effective.get("include_source_time_notes"), True)
    effective["inventory_limit"] = _setup_positive_int(effective.get("inventory_limit"), 500, 1, 10000)
    effective["inventory_exclude_bins"] = (
        str(effective.get("inventory_exclude_bins")).strip()
        if effective.get("inventory_exclude_bins") is not None
        else ""
    )
    effective["analysis_summary_style"] = _normalize_setup_choice(
        effective.get("analysis_summary_style"),
        ["full", "concise", "creative", "technical"],
        aliases={
            "assistant_editor": "creative",
            "assistant": "creative",
            "editor": "creative",
            "producer": "creative",
            "qc": "technical",
            "qc_focus": "technical",
            "qc_focused": "technical",
        },
    ) or "concise"
    effective["report_format"] = _normalize_setup_choice(effective.get("report_format"), ["compact", "full", "machine_readable"]) or "compact"
    effective["source_trust"] = _normalize_setup_choice(
        effective.get("source_trust"),
        ["auto", "filename", "low", "medium", "high"],
        aliases={"none": "auto", "default": "auto"},
    ) or "auto"
    effective["default_depth"] = _normalize_setup_choice(
        effective.get("default_depth"),
        ["quick", "standard", "deep"],
    ) or "standard"
    try:
        sample_frames_raw = effective.get("default_sample_frames")
        sample_frames_int = int(sample_frames_raw) if sample_frames_raw not in (None, "") else 8
    except (TypeError, ValueError):
        sample_frames_int = 8
    effective["default_sample_frames"] = max(0, min(48, sample_frames_int))
    # sampling_mode_default normalizes to a canonical mode, or None when unset /
    # "ask" (None means "not yet chosen" → first-run prompt fires).
    effective["sampling_mode_default"] = _normalize_sampling_mode_default(effective.get("sampling_mode_default"))

    def _pos_number(value: Any, fallback: float) -> float:
        try:
            f = float(value)
        except (TypeError, ValueError):
            return fallback
        return f if f > 0 else fallback

    effective["sampling_frames_per_minute"] = _pos_number(
        effective.get("sampling_frames_per_minute"), DEFAULT_FRAMES_PER_MINUTE
    )
    effective["sampling_frame_floor"] = int(_pos_number(
        effective.get("sampling_frame_floor"), DEFAULT_FRAME_FLOOR
    ))
    ceiling = int(_pos_number(
        effective.get("sampling_frame_ceiling"), DEFAULT_FRAME_CEILING
    ))
    if ceiling < effective["sampling_frame_floor"]:
        ceiling = effective["sampling_frame_floor"]
    effective["sampling_frame_ceiling"] = ceiling
    effective["default_post_operation_page"] = _normalize_setup_choice(
        effective.get("default_post_operation_page"),
        ["stay_put", "media", "cut", "edit", "fusion", "color", "fairlight", "deliver"],
        aliases={"media_pool": "media", "none": "stay_put"},
    ) or "stay_put"
    effective["marker_custom_data"] = _normalize_setup_choice(effective.get("marker_custom_data"), ["namespaced", "minimal"]) or "namespaced"
    effective["metadata_writeback_default"] = _media_analysis_bool(effective.get("metadata_writeback_default"), True)
    effective["ask_before_metadata_publish"] = _media_analysis_bool(effective.get("ask_before_metadata_publish"), True)
    effective["dry_run_first_default"] = _media_analysis_bool(effective.get("dry_run_first_default"), True)
    return effective


